        assertThat(p2Item.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_p2))
    }

    @Test
    fun `GIVEN p2 not present WHEN createMenu THEN p2 menu item not created`() {
        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(mockSavedTag()) // item 2
            add(mockLikedTag()) // item 3
            add(mockA8CTag()) // item 4
            add(createCustomListTag("custom-list-1")) // item 5
        }

        val menu = helper.createMenu(tags)

        val p2Item = menu
            .findSingleItem { it.text == UiStringRes(R.string.reader_dropdown_menu_p2) }
